type Project = { id: string; name: string; slug: string; rootPath: string; createdAt: string };
type FileTreeNode = { name: string; path: string; kind: 'directory' | 'file'; children?: FileTreeNode[] };
type TextFile = { content: string; version: string; readOnly: boolean };
type JobRecord = { id:string; title:string; company:string; location?:string; remoteType:string; description?:string; salaryRange?:string; applyUrl:string; sourceUrl:string; sourceType:string; status:string; createdAt:string };
type Packet = { id:string; jobId:string; relativePath:string; status:string; createdAt:string };
type SourceConfig = { id:string; name:string; actorName:string; mcpServerUrl:string; inputTemplateJson:string };
type ImportResult = { imported:number; skipped:number; skippedReasons:string[] };
type ChatMessage = { id:string; role:string; content:string; linkedFilePath?:string; linkedJobId?:string; createdAt:string };
type ChatSession = { id:string; projectSlug:string; title:string; createdAt:string; updatedAt:string };
type CodexStatus = { installed:boolean; connected:boolean; authMode?:string; version?:string; detail:string };
type ApifyMcpStatus = { connected:boolean; detail:string };
type TavilyStatus = { connected:boolean; detail:string; maskedKey?:string };
type AgentRunEvent = { runId:string; kind:string; text:string };
type HuntRunOutput = { folderPath:string; resultsPath:string };
type HuntProgressStep = { label:string; status:'pending'|'active'|'done'|'error' };
type HuntProgress = { running:boolean; title:string; progress:number; detail:string; steps:HuntProgressStep[]; resultPath?:string };

