async function call<T>(cmd: string, args?: Record<string, unknown>): Promise<T> { return invoke<T>(cmd, args); }
async function fileBytes(file: File): Promise<number[]> { return Array.from(new Uint8Array(await file.arrayBuffer())); }
function Portal({children}:{children:React.ReactNode}){ return createPortal(children, document.body); }

function visibleTree(node: FileTreeNode): FileTreeNode | null {
  const hidden = ['project.json', 'profile', 'chats', 'sources', '.DS_Store'];
  if (node.path && hidden.includes(node.name)) return null;
  return {...node, children: node.children?.map(visibleTree).filter(Boolean) as FileTreeNode[] | undefined};
}

function TreeNode({ node, onOpen, active, onContext }: { node: FileTreeNode; onOpen: (node: FileTreeNode) => void; active?: string; onContext:(node:FileTreeNode,event:React.MouseEvent)=>void }) {
  const [open, setOpen] = React.useState(node.path === ''); const isDir = node.kind === 'directory';
  return <div><button className={`tree-row ${active === node.path ? 'active' : ''}`} onContextMenu={(e)=>{e.stopPropagation();onContext(node,e)}} onClick={() => isDir ? setOpen(!open) : onOpen(node)}>{isDir ? (open ? <FolderOpen size={14}/> : <Folder size={14}/>) : <FileText size={14}/>}<span>{node.name === '.' ? 'Project' : node.name}</span>{isDir && <ChevronRight className={open ? 'rotate' : ''} size={13}/>}</button>{isDir && open && node.children && <div className="tree-children">{node.children.map(child => <TreeNode key={child.path || child.name} node={child} onOpen={onOpen} active={active} onContext={onContext}/>)}</div>}</div>;
}

function App() {
  const [project, setProject] = React.useState<Project | null>(null); const [projects,setProjects]=React.useState<Project[]>([]); const [tree, setTree] = React.useState<FileTreeNode | null>(null);
  const [selectedPath, setSelectedPath] = React.useState(''); const [content, setContent] = React.useState(''); const [readOnly, setReadOnly] = React.useState(false); const [dirty, setDirty] = React.useState(false);
  const [status, setStatus] = React.useState('Loading projects…'); const [debugLogs,setDebugLogs]=React.useState<string[]>([]); const [projectName, setProjectName] = React.useState('My 2026 Job Search'); const [jobs,setJobs]=React.useState<JobRecord[]>([]); const [packets,setPackets]=React.useState<Packet[]>([]);
  const [role1,setRole1]=React.useState(''); const [role2,setRole2]=React.useState(''); const [role3,setRole3]=React.useState('');
  const [location,setLocation]=React.useState('United States, Worldwide'); const [workMode,setWorkMode]=React.useState('Remote'); const [seniority,setSeniority]=React.useState('Senior'); const [experience,setExperience]=React.useState('1–3 years'); const [minSalary,setMinSalary]=React.useState('Any');
  const [includeKeywords,setIncludeKeywords]=React.useState(''); const [excludeKeywords,setExcludeKeywords]=React.useState(''); const [postedWithin,setPostedWithin]=React.useState('1 week');
  const [selectedSites,setSelectedSites]=React.useState<string[]>(DEFAULT_REMOTE_SITES); const [sourceUrls,setSourceUrls]=React.useState('');
  const [importPath]=React.useState('sources/imports/sample-raw.json'); const [importResult,setImportResult]=React.useState<ImportResult|null>(null);
  const [contextMenu,setContextMenu]=React.useState<{x:number;y:number;node:FileTreeNode}|null>(null); const [uploadParent,setUploadParent]=React.useState(''); const [newFileParent,setNewFileParent]=React.useState<string|null>(null); const [newFileName,setNewFileName]=React.useState('note.md'); const [pendingDeletePath,setPendingDeletePath]=React.useState<string|null>(null); const [settingsOpen,setSettingsOpen]=React.useState(false); const [huntCreating,setHuntCreating]=React.useState(false); const [huntProgress,setHuntProgress]=React.useState<HuntProgress|null>(null); const [huntMaxResults,setHuntMaxResults]=React.useState(()=>localStorage.getItem('huntMaxResults')||'100'); const [codex,setCodex]=React.useState<CodexStatus|null>(null); const [apify,setApify]=React.useState<ApifyMcpStatus|null>(null); const [tavily,setTavily]=React.useState<TavilyStatus|null>(null); const uploadInputRef=React.useRef<HTMLInputElement|null>(null); const resumeInputRef=React.useRef<HTMLInputElement|null>(null);
  const resumeName = React.useMemo(()=>{ const profile=tree?.children?.find(n=>n.name==='profile'); return profile?.children?.find(n=>n.name.startsWith('resume_current'))?.name || ''; },[tree]);

  const debugLog = React.useCallback((message:string) => { const line = `${new Date().toLocaleTimeString()}  ${message}`; setDebugLogs(prev=>[line,...prev].slice(0,80)); setStatus(message); }, []);
  const refreshConnections = React.useCallback(async()=>{ const [c,a,t]=await Promise.all([call<CodexStatus>('codex_status').catch(()=>({installed:false,connected:false,detail:'Could not check Codex'})), call<ApifyMcpStatus>('apify_mcp_status').catch(()=>({connected:false,detail:'Could not check Apify API'})), call<TavilyStatus>('tavily_status').catch(()=>({connected:false,detail:'Could not check Tavily'}))]); setCodex(c); setApify(a); setTavily(t); },[]);
  const refreshTree = React.useCallback(async (slug = project?.slug) => { if (!slug) return; setTree(await call<FileTreeNode>('list_workspace_tree', { projectSlug: slug })); }, [project?.slug]);
  const refreshJobs = React.useCallback(async(slug = project?.slug)=>{ if(slug) setJobs(await call<JobRecord[]>('list_jobs',{projectSlug:slug,status:'all'})); },[project?.slug]);
  const refreshPackets = React.useCallback(async(slug = project?.slug)=>{ if(slug) setPackets(await call<Packet[]>('list_packets',{projectSlug:slug})); },[project?.slug]);
  const openProject = React.useCallback(async (p: Project) => { setProject(p); setSelectedPath(''); setContent(''); setReadOnly(false); setDirty(false); setTree(await call<FileTreeNode>('list_workspace_tree', { projectSlug: p.slug })); setJobs(await call<JobRecord[]>('list_jobs', { projectSlug: p.slug, status: 'all' })); setPackets(await call<Packet[]>('list_packets', { projectSlug: p.slug })); await call<SourceConfig|null>('get_source_config',{projectSlug:p.slug}).catch(()=>null); setStatus(`Opened ${p.name}`); }, []);
  React.useEffect(() => { void refreshConnections(); void (async()=>{ try { const ps = await call<Project[]>('list_projects'); setProjects(ps); if (ps.length) await openProject(ps[0]); else setStatus('No project open'); } catch(e) { setStatus(String(e)); } })(); }, [openProject,refreshConnections]);
  React.useEffect(()=>{ localStorage.setItem('huntMaxResults', huntMaxResults); },[huntMaxResults]);

  const createProject = async () => { try { setStatus('Creating project…'); const p = await call<Project>('create_project', { name: projectName }); setProjects(prev=>[p,...prev.filter(x=>x.slug!==p.slug)]); await openProject(p); } catch (e) { setStatus(String(e)); } };
  const openFile = async (node: FileTreeNode) => { if (!project || node.kind !== 'file') return; try { const file = await call<TextFile>('read_text_file', { projectSlug: project.slug, path: node.path }); setSelectedPath(node.path); setContent(file.content); setReadOnly(file.readOnly); setDirty(false); setStatus(file.readOnly ? `${node.name} is read-only` : `Opened ${node.name}`); } catch (e) { setStatus(String(e)); } };
  const openPath = async(path:string)=>openFile({name:path.split('/').pop()||path,path,kind:'file'});
  const saveFile = React.useCallback(async () => { if (!project || !selectedPath || readOnly) return; try { await call('write_text_file', { input: { projectSlug: project.slug, path: selectedPath, content } }); setDirty(false); setStatus(`Saved ${selectedPath}`); await refreshTree(); } catch (e) { setStatus(String(e)); } }, [project, selectedPath, readOnly, content, refreshTree]);
  React.useEffect(() => { const handler = (event: KeyboardEvent) => { if ((event.metaKey || event.ctrlKey) && event.key.toLowerCase() === 's') { event.preventDefault(); void saveFile(); } }; window.addEventListener('keydown', handler); return () => window.removeEventListener('keydown', handler); }, [saveFile]);

  const setHuntStep = (index:number, progress:number, detail:string, status:'active'|'done'|'error'='active') => setHuntProgress(prev=>prev?{...prev,progress,detail,steps:prev.steps.map((s,i)=>i<index?{...s,status:'done'}:i===index?{...s,status}:s)}:prev);
  const applyHuntMarker = (text:string, resultPath?:string) => {
    const regex = /\[(HUNT_PROGRESS|HUNT_DONE|HUNT_ERROR)\]\s*([^\[]*)/g;
    let match:RegExpExecArray|null;
    while((match=regex.exec(text))){
      const kind=match[1]; const detail=match[2].replace(/[\r\n]+/g,' ').trim();
      if(!detail && kind==='HUNT_PROGRESS') continue;
      debugLog(`Hunt marker: ${kind} ${detail}`);
      if(kind==='HUNT_PROGRESS') setHuntProgress(prev=>prev?{...prev,progress:Math.min(94,Math.max(prev.progress+3,86)),detail:detail||prev.detail,steps:prev.steps.map((s,i)=>i<5?{...s,status:'done'}:i===5?{...s,status:'active'}:s)}:prev);
      if(kind==='HUNT_DONE') setHuntProgress(prev=>prev?{...prev,running:false,progress:100,detail:detail||'Hunt complete.',resultPath,steps:prev.steps.map(s=>({...s,status:'done'}))}:prev);
      if(kind==='HUNT_ERROR') setHuntProgress(prev=>prev?{...prev,running:false,detail:detail||'Hunt failed.',resultPath,steps:prev.steps.map(s=>s.status==='active'?{...s,status:'error'}:s)}:prev);
    }
  };
  const generateHuntFiles = async(huntName:string)=>{ if(!project) return null; const roles=[role1,role2,role3].filter(Boolean); const steps=['Preparing hunt run','Validating connections','Writing results.md','Opening results.md','Running Apify API','Curating results']; setHuntCreating(true); setHuntProgress({running:true,title:huntName,progress:4,detail:'Starting HuntBrief task…',steps:steps.map((label,i)=>({label,status:i===0?'active':'pending'}))}); debugLog(`Start Hunting: creating run "${huntName}" · ${workMode} · sources: ${selectedSites.join(', ') || 'none'} · max ${huntMaxResults}`); try{ setHuntStep(0,10,'Creating hunt folder…'); await new Promise(r=>setTimeout(r,120)); setHuntStep(1,20,'Checking Apify API and selected sources…'); if(!apify?.connected) debugLog('Start Hunting warning: Apify API is not connected in Settings. The backend run may fail until it is connected.'); await new Promise(r=>setTimeout(r,120)); setHuntStep(2,32,'Writing results.md…'); const out=await call<HuntRunOutput>('create_hunt_run',{input:{projectSlug:project.slug,name:huntName,roles,location,workMode,seniority,experience,minSalary,includeKeywords,excludeKeywords,postedWithin,selectedSites,maxItems:Number(huntMaxResults)}}); debugLog(`Start Hunting: wrote ${out.resultsPath}`); setStatus(`Created hunt run: ${huntName}`); await refreshTree(); debugLog(`Start Hunting: refreshed file tree`); setHuntStep(3,42,`Opening ${out.resultsPath}…`); await openPath(out.resultsPath); debugLog(`Start Hunting: opened ${out.resultsPath}`); setHuntStep(4,52,'Starting Apify Actor API run…'); const runId=crypto.randomUUID(); const onEvent=new Channel<AgentRunEvent>(); await new Promise<void>((resolve,reject)=>{ onEvent.onmessage=(ev)=>{ if(ev.runId!==runId)return; debugLog(`Hunt backend: ${ev.kind} ${ev.text.slice(0,120)}`); if(ev.kind==='started'||ev.kind==='status'){ const isFetch=ev.text.includes('fetched')||ev.text.includes('reading dataset'); setHuntProgress(prev=>prev?{...prev,progress:Math.min(isFetch?90:82,Math.max(prev.progress,prev.progress+(isFetch?4:2))),detail:ev.text,steps:prev.steps.map((s,i)=>i<4?{...s,status:'done'}:i===4?{...s,status:'active'}:s)}:prev); if(isFetch) setHuntStep(5,86,'Curating actor output into results.md…'); } if(ev.kind==='completed'){ setHuntProgress(prev=>prev?{...prev,running:false,progress:100,detail:ev.text||'Hunt complete. Results were written to results.md.',resultPath:out.resultsPath,steps:prev.steps.map(s=>({...s,status:'done'}))}:prev); resolve(); } if(ev.kind==='failed'||ev.kind==='cancelled'){ setHuntProgress(prev=>prev?{...prev,running:false,detail:`Hunt ${ev.kind}: ${ev.text}`,resultPath:out.resultsPath,steps:prev.steps.map(s=>s.status==='active'?{...s,status:'error'}:s)}:prev); reject(new Error(ev.text)); } }; call<string>('start_hunt_apify',{input:{projectSlug:project.slug,name:huntName,roles,location,workMode,seniority,experience,minSalary,includeKeywords,excludeKeywords,postedWithin,selectedSites,maxItems:Number(huntMaxResults),resultsPath:out.resultsPath,runId},onEvent}).then(()=>debugLog(`Hunt backend: Apify run started ${runId}`)).catch(reject); }); await refreshTree(); await openPath(out.resultsPath); debugLog(`Start Hunting: completed backend run for ${out.folderPath}`); return out; }catch(e){debugLog(`Start Hunting failed: ${String(e)}`); setStatus(String(e)); setHuntProgress(prev=>prev?{...prev,running:false,detail:`Failed: ${String(e)}`,steps:prev.steps.map(s=>s.status==='active'?{...s,status:'error'}:s)}:prev); return null;} finally{ setHuntCreating(false); } };
  const importJobs = async()=>{ if(!project) return; try{ const r=await call<ImportResult>('import_apify_json',{input:{projectSlug:project.slug,path:importPath}}); setImportResult(r); setStatus(`Imported ${r.imported} jobs · skipped ${r.skipped}`); await refreshJobs(); await refreshTree(); }catch(e){setStatus(String(e));} };
  const handleTreeContext=(node:FileTreeNode,event:React.MouseEvent)=>{ event.preventDefault(); setContextMenu({x:event.clientX,y:event.clientY,node}); };
  const startNewFile=(parent:string)=>{ setNewFileParent(parent); setNewFileName('note.md'); setContextMenu(null); };
  const createNewFile=async()=>{ if(!project||newFileParent===null||!newFileName.trim())return; try{ const rel=await call<string>('create_text_file',{input:{projectSlug:project.slug,parentPath:newFileParent,name:newFileName.trim(),content:''}}); setStatus(`Created ${rel}`); setNewFileParent(null); await refreshTree(); await openPath(rel); }catch(e){setStatus(String(e));} };
  const requestDeleteFile=(path:string)=>{ setPendingDeletePath(path); setContextMenu(null); };
  const deleteFile=async()=>{ if(!project||!pendingDeletePath)return; const path=pendingDeletePath; try{ debugLog(`Deleting ${path}…`); await call('delete_project_file',{input:{projectSlug:project.slug,path}}); debugLog(`Deleted ${path}`); if(selectedPath===path){setSelectedPath('');setContent('');setDirty(false);} setPendingDeletePath(null); await refreshTree(); }catch(e){debugLog(`Delete failed: ${String(e)}`);} };
  const revealPath=async(path:string)=>{ if(!project)return; try{ await call('reveal_project_path',{input:{projectSlug:project.slug,path}}); }catch(e){setStatus(String(e));} finally{setContextMenu(null);} };
  const pickUpload=(parent:string)=>{ setUploadParent(parent); uploadInputRef.current?.click(); setContextMenu(null); };
  const uploadPicked=async(file:File|null)=>{ if(!project||!file)return; try{ const rel=await call<string>('upload_project_file',{input:{projectSlug:project.slug,parentPath:uploadParent,name:file.name,bytes:await fileBytes(file)}}); setStatus(`Uploaded ${rel}`); await refreshTree(); }catch(e){setStatus(String(e));} };
  const uploadResume=async(file:File|null)=>{ if(!project||!file)return; try{ const rel=await call<string>('upload_resume',{input:{projectSlug:project.slug,name:file.name,bytes:await fileBytes(file)}}); setStatus(`Resume uploaded: ${rel}`); await refreshTree(); }catch(e){setStatus(String(e));} };
  const removeResume=async()=>{ if(!project)return; try{ await call('remove_resume',{projectSlug:project.slug}); setStatus('Removed resume'); await refreshTree(); }catch(e){setStatus(String(e));} };
  React.useEffect(()=>{ const onKey=(e:KeyboardEvent)=>{ if(e.key==='Escape'){ setNewFileParent(null); setPendingDeletePath(null); } }; window.addEventListener('keydown',onKey); return()=>window.removeEventListener('keydown',onKey); },[]);

  return <main className="workspace-frame" onClick={()=>setContextMenu(null)}><input ref={uploadInputRef} type="file" hidden onChange={e=>void uploadPicked(e.target.files?.[0]||null)}/><input ref={resumeInputRef} type="file" hidden accept=".pdf,.md,.txt,.doc,.docx" onChange={e=>void uploadResume(e.target.files?.[0]||null)}/><section className="hunt-brief-panel"><HuntBriefPanel project={project} projectName={projectName} setProjectName={setProjectName} createProject={createProject} jobs={jobs} packets={packets} role1={role1} setRole1={setRole1} role2={role2} setRole2={setRole2} role3={role3} setRole3={setRole3} location={location} setLocation={setLocation} workMode={workMode} setWorkMode={setWorkMode} seniority={seniority} setSeniority={setSeniority} experience={experience} setExperience={setExperience} minSalary={minSalary} setMinSalary={setMinSalary} includeKeywords={includeKeywords} setIncludeKeywords={setIncludeKeywords} excludeKeywords={excludeKeywords} setExcludeKeywords={setExcludeKeywords} postedWithin={postedWithin} setPostedWithin={setPostedWithin} selectedSites={selectedSites} setSelectedSites={setSelectedSites} sourceUrls={sourceUrls} setSourceUrls={setSourceUrls} importJobs={importJobs} importResult={importResult} resumeName={resumeName} uploadResume={()=>resumeInputRef.current?.click()} removeResume={removeResume} debugLog={debugLog} huntCreating={huntCreating} huntProgress={huntProgress} clearHuntProgress={()=>setHuntProgress(null)} openPath={openPath}/></section><aside className="files-panel"><div className="files-head"><strong>Files</strong><small>{project?.slug ?? 'No project'}</small></div><div className="file-tree-scroll">{tree && visibleTree(tree) ? <TreeNode node={visibleTree(tree)!} onOpen={openFile} active={selectedPath} onContext={handleTreeContext}/> : <p className="muted small">Create or open a project.</p>}</div><button className="settings-bottom" disabled={!project} onClick={()=>setSettingsOpen(true)}><Settings size={15}/> Settings</button></aside><section className="editor-panel"><EditorView selectedPath={selectedPath} content={content} setContent={(v:string)=>{setContent(v); setDirty(true);}} readOnly={readOnly} dirty={dirty} saveFile={saveFile} debugLogs={debugLogs}/></section><AgentPanel project={project} selectedPath={selectedPath} setStatus={setStatus} debugLog={debugLog} refreshTree={refreshTree} openPath={openPath} onStartHunting={generateHuntFiles}/>{contextMenu&&<div className="context-menu" style={{left:contextMenu.x,top:contextMenu.y}} onClick={e=>e.stopPropagation()}>{contextMenu.node.kind==='directory'&&<><button onClick={()=>startNewFile(contextMenu.node.path)}>New File…</button><button onClick={()=>pickUpload(contextMenu.node.path)}>Upload File…</button></>}{contextMenu.node.kind==='file'&&<button className="danger" onClick={()=>requestDeleteFile(contextMenu.node.path)}>Delete File…</button>}<button onClick={()=>void revealPath(contextMenu.node.path)}>Reveal in Finder</button></div>}{newFileParent!==null&&<Portal><div className="modal-backdrop" onClick={()=>setNewFileParent(null)}><div className="native-sheet" onClick={e=>e.stopPropagation()}><strong>New file</strong><p>Create a file in {newFileParent || 'Project'}.</p><input autoFocus value={newFileName} onChange={e=>setNewFileName(e.target.value)} onKeyDown={e=>{if(e.key==='Enter')void createNewFile(); if(e.key==='Escape')setNewFileParent(null);}}/><div className="popover-actions"><button onClick={()=>setNewFileParent(null)}>Cancel</button><button className="primary" onClick={()=>void createNewFile()}>Create</button></div></div></div></Portal>}{pendingDeletePath&&<Portal><div className="modal-backdrop" onClick={()=>setPendingDeletePath(null)}><div className="native-sheet" onClick={e=>e.stopPropagation()}><strong>Delete file?</strong><p>This will permanently delete {pendingDeletePath}.</p><div className="popover-actions"><button onClick={()=>setPendingDeletePath(null)}>Cancel</button><button className="danger-button" onClick={()=>void deleteFile()}>Delete</button></div></div></div></Portal>}{settingsOpen&&<SettingsModal codex={codex} setCodex={setCodex} apify={apify} setApify={setApify} tavily={tavily} setTavily={setTavily} huntMaxResults={huntMaxResults} setHuntMaxResults={setHuntMaxResults} refreshConnections={refreshConnections} debugLog={debugLog} onClose={()=>setSettingsOpen(false)}/>}<footer className="statusbar">{status}</footer></main>;
}

function SettingsModal({codex,setCodex,apify,setApify,tavily,setTavily,huntMaxResults,setHuntMaxResults,refreshConnections,debugLog,onClose}:{codex:CodexStatus|null;setCodex:(s:CodexStatus)=>void;apify:ApifyMcpStatus|null;setApify:(s:ApifyMcpStatus)=>void;tavily:TavilyStatus|null;setTavily:(s:TavilyStatus)=>void;huntMaxResults:string;setHuntMaxResults:(s:string)=>void;refreshConnections:()=>Promise<void>;debugLog?:(s:string)=>void;onClose:()=>void}){
  const [codexBusy,setCodexBusy]=React.useState(false); const [apifyToken,setApifyToken]=React.useState(''); const [apifyBusy,setApifyBusy]=React.useState(false); const [tavilyKey,setTavilyKey]=React.useState(''); const [tavilyBusy,setTavilyBusy]=React.useState(false); const [confirmAction,setConfirmAction]=React.useState<null|'codex'|'apify'|'tavily'>(null);
  React.useEffect(()=>{ const onKey=(e:KeyboardEvent)=>{ if(e.key==='Escape') onClose(); }; window.addEventListener('keydown',onKey); return()=>window.removeEventListener('keydown',onKey); },[onClose]);
  const connectCodex=async()=>{ if(codexBusy)return; if(codex?.connected){ setConfirmAction('codex'); return; } setCodexBusy(true); try{ const s=await call<CodexStatus>('codex_connect'); setCodex(s); debugLog?.(`Codex: ${s.detail}`); }catch(e){ const s={installed:false,connected:false,detail:String(e)}; setCodex(s); debugLog?.(`Codex failed: ${String(e)}`); } finally{ setCodexBusy(false); } };
  const disconnectCodex=async()=>{ try{ const s=await call<CodexStatus>('codex_disconnect'); setCodex(s); debugLog?.(`Codex: ${s.detail}`); }catch(e){ debugLog?.(`Codex disconnect failed: ${String(e)}`); } finally{ setConfirmAction(null); } };
  const connectApify=async()=>{ if(apify?.connected){ setConfirmAction('apify'); return; } if(!apifyToken.trim()){ debugLog?.('Paste an Apify API token first.'); return; } setApifyBusy(true); try{ const s=await call<ApifyMcpStatus>('apify_mcp_connect',{input:{token:apifyToken}}); setApify(s); setApifyToken(''); debugLog?.(`Apify API: ${s.detail}`); }catch(e){ const s={connected:false,detail:String(e)}; setApify(s); debugLog?.(`Apify API failed: ${String(e)}`); } finally{ setApifyBusy(false); } };
  const disconnectApify=async()=>{ try{ const s=await call<ApifyMcpStatus>('apify_mcp_disconnect'); setApify(s); debugLog?.(`Apify API: ${s.detail}`); }catch(e){ debugLog?.(`Apify disconnect failed: ${String(e)}`); } finally{ setConfirmAction(null); } };
  const connectTavily=async()=>{ if(tavily?.connected){ setConfirmAction('tavily'); return; } if(!tavilyKey.trim()){ debugLog?.('Paste a Tavily API key first.'); return; } setTavilyBusy(true); try{ const s=await call<TavilyStatus>('tavily_connect',{input:{apiKey:tavilyKey}}); setTavily(s); setTavilyKey(''); debugLog?.(`Tavily: ${s.detail}`); }catch(e){ const s={connected:false,detail:String(e)}; setTavily(s); debugLog?.(`Tavily failed: ${String(e)}`); } finally{ setTavilyBusy(false); } };
  const disconnectTavily=async()=>{ try{ const s=await call<TavilyStatus>('tavily_disconnect'); setTavily(s); debugLog?.(`Tavily: ${s.detail}`); }catch(e){ debugLog?.(`Tavily disconnect failed: ${String(e)}`); } finally{ setConfirmAction(null); } };
  return <Portal><div className="modal-backdrop" onClick={onClose}><div className="settings-sheet" onClick={e=>e.stopPropagation()}><div className="settings-head"><strong>Settings</strong><div className="settings-head-actions"><button onClick={()=>void refreshConnections()}>Refresh</button><button className="settings-close" onClick={onClose}>×</button></div></div><div className="settings-field"><label>Max scrape results<select value={huntMaxResults} onChange={e=>setHuntMaxResults(e.target.value)}><option value="25">25</option><option value="50">50</option><option value="75">75</option><option value="100">100</option></select></label></div><Connection name="Codex" connected={!!codex?.connected} busy={codexBusy} detail={codexBusy?'Checking Codex…':(codex?.connected?(codex.authMode||'Connected'):(codex?.installed?'Sign in with ChatGPT':(codex?.detail||'Not checked yet')))} onToggle={connectCodex}/><div className="settings-connection"><Connection name="Apify API" connected={!!apify?.connected} busy={apifyBusy} detail={apify?.detail||'Not checked yet'} onToggle={connectApify}/>{!apify?.connected&&<input value={apifyToken} onChange={e=>setApifyToken(e.target.value)} placeholder="apify_api_..."/>}</div><div className={`settings-connection ${tavilyBusy?'connecting':''}`}><Connection name="Tavily" connected={!!tavily?.connected} busy={tavilyBusy} detail={tavilyBusy?'Testing Tavily connection…':(tavily?.connected?(tavily.maskedKey||'API key saved'):(tavily?.detail||'Needs Tavily API key'))} onToggle={connectTavily}/>{!tavily?.connected&&<><button className="link-button" disabled={tavilyBusy} onClick={()=>void call('open_external_url',{url:'https://app.tavily.com/'})}>Get Tavily API key ↗</button><input value={tavilyKey} onChange={e=>setTavilyKey(e.target.value)} placeholder="tvly-..." type="password" disabled={tavilyBusy}/><small>{tavilyBusy?<><span className="mini-spinner"/> Connecting and testing with Tavily Search…</>:'Tests against Tavily Search API before saving.'}</small></>}</div>{confirmAction&&<div className="settings-confirm"><strong>{confirmAction==='codex'?'Disconnect Codex?':confirmAction==='apify'?'Disconnect Apify API?':'Disconnect Tavily?'}</strong><div className="popover-actions"><button onClick={()=>setConfirmAction(null)}>Cancel</button><button className="danger-button" onClick={()=>void (confirmAction==='codex'?disconnectCodex():confirmAction==='apify'?disconnectApify():disconnectTavily())}>Disconnect</button></div></div>}</div></div></Portal>;
}

function MultiSelect({label,value,onChange,options,searchable=false,className=''}:{label:string;value:string;onChange:(v:string)=>void;options:string[];searchable?:boolean;className?:string}){
  const [open,setOpen]=React.useState(false); const [query,setQuery]=React.useState('');
  const selected=value.split(',').map(v=>v.trim()).filter(Boolean);
  const filtered=options.filter(option=>option.toLowerCase().includes(query.toLowerCase()));
  const toggle=(option:string)=>{ const next=selected.includes(option)?selected.filter(v=>v!==option):[...selected,option]; onChange(next.join(', ')); };
  return <label className={`multi-select-field ${className}`}>{label}<button type="button" className="multi-select-trigger" onClick={()=>setOpen(!open)}><span>{selected.length?selected.join(', '):`Select ${label.toLowerCase()}`}</span><ChevronRight className={open?'rotate':''} size={13}/></button>{open&&<div className="multi-select-menu">{searchable&&<input className="multi-select-search" autoFocus value={query} onChange={e=>setQuery(e.target.value)} onClick={e=>e.stopPropagation()} placeholder={`Search ${label.toLowerCase()}…`}/>}<div className="multi-select-options">{filtered.map(option=><button type="button" key={option} onClick={()=>toggle(option)}>{selected.includes(option)?<CheckCircle2 size={13}/>:<Circle size={13}/>}<span>{option}</span></button>)}{!filtered.length&&<div className="multi-select-empty">No matches</div>}</div></div>}</label>;
}

function HuntBriefPanel(props:any){
  const {project,projectName,setProjectName,createProject,role1,setRole1,role2,setRole2,role3,setRole3,location,setLocation,workMode,setWorkMode,seniority,setSeniority,experience,setExperience,minSalary,setMinSalary,includeKeywords,setIncludeKeywords,excludeKeywords,setExcludeKeywords,postedWithin,setPostedWithin,selectedSites,setSelectedSites,importJobs,importResult,debugLog,huntCreating,huntProgress,clearHuntProgress,openPath}=props;
  const [tab,setTab]=React.useState<'find'|'import'>('find');
  const [importText,setImportText]=React.useState(''); const importFileRef=React.useRef<HTMLInputElement|null>(null);
  const importFile=async(file:File|null)=>{ if(!file)return; setImportText(`Imported file: ${file.name}\n${importText}`); debugLog?.(`Queued ${file.name} for link extraction`); };
  const toggleSite=(site:string)=>setSelectedSites((prev:string[])=>prev.includes(site)?prev.filter(s=>s!==site):[...prev,site]);
  const sourceSites=workMode==='Remote'?REMOTE_JOB_SITES:STANDARD_JOB_SITES;
  React.useEffect(()=>{ const defaults=workMode==='Remote'?DEFAULT_REMOTE_SITES:DEFAULT_STANDARD_SITES; setSelectedSites((prev:string[])=>prev.some(site=>sourceSites.includes(site))?prev.filter(site=>sourceSites.includes(site)):defaults); },[workMode]);
  const extractedLinks=(importText.match(/https?:\/\/\S+/g)||[]).length;
  if(!project) return <div className="project-empty"><div><h1>Create your job-search workspace</h1><p>Local files stay under <code>~/.dropthegrind/workspace</code>.</p></div><div className="create-card"><input value={projectName} onChange={(e:any)=>setProjectName(e.target.value)} /><button className="primary" onClick={createProject}><Plus size={15}/> Create Project</button></div></div>;
  return <div className={`hunt-unified ${huntCreating?'processing':''}`}>{huntCreating&&<div className="hunt-processing-bar"/>}<input ref={importFileRef} type="file" hidden accept=".md,.csv,.pdf,.txt" onChange={e=>void importFile(e.target.files?.[0]||null)}/><div className="hunt-header"><div className="brief-title"><Target size={16}/><div><h2>{project.name}</h2><p>Find roles from curated sources, or import job links into the same HuntBrief flow.</p></div></div><div className="hunt-tabs"><button className={tab==='find'?'active':''} onClick={()=>setTab('find')}>Find Jobs</button><button className={tab==='import'?'active':''} onClick={()=>setTab('import')}>Import Links</button></div></div>{huntProgress?<HuntProgressDashboard progress={huntProgress} onOpen={()=>huntProgress.resultPath&&openPath?.(huntProgress.resultPath)} onReset={clearHuntProgress}/>:tab==='find'?<div className="find-jobs-native"><div className="target-grid hunt-form-grid"><label>Role 1<input value={role1} onChange={(e)=>setRole1(e.target.value)} placeholder="e.g. AI Engineer"/></label><label>Role 2<input value={role2} onChange={(e)=>setRole2(e.target.value)} placeholder="e.g. AI Automation"/></label><label>Role 3<input value={role3} onChange={(e)=>setRole3(e.target.value)} placeholder="Optional role"/></label><MultiSelect label="Seniority" value={seniority} onChange={setSeniority} options={['Internship','Entry level','Associate','Mid-Senior level','Senior','Director','Executive']}/><MultiSelect label="Experience" value={experience} onChange={setExperience} options={['0–1 years','1–3 years','3–5 years','5–8 years','8+ years']}/><label>Min salary<select value={minSalary} onChange={(e)=>setMinSalary(e.target.value)}><option>Any</option><option>10K&gt;</option><option>50K&gt;</option><option>100K&gt;</option><option>150K&gt;</option><option>200K&gt;</option></select></label><label>Include keywords<input value={includeKeywords} onChange={(e)=>setIncludeKeywords(e.target.value)} placeholder="e.g. AI, Automation, Python"/></label><label>Avoid keywords<input value={excludeKeywords} onChange={(e)=>setExcludeKeywords(e.target.value)} placeholder="e.g. commission-only, defense"/></label><label>Posted within<select value={postedWithin} onChange={(e)=>setPostedWithin(e.target.value)}><option>1 week</option><option>3 weeks</option><option>1 month</option><option>3 months</option></select></label><MultiSelect className="location-row" label="Location" value={location} onChange={setLocation} options={COUNTRIES} searchable/></div><div className="source-strip"><div className="source-mode-head"><div className="mode-tabs"><button className={workMode==='Standard'?'active':''} onClick={()=>setWorkMode('Standard')}>Standard</button><button className={workMode==='Remote'?'active':''} onClick={()=>setWorkMode('Remote')}>Remote</button></div></div><div className="site-pill-grid native-site-grid">{sourceSites.map(site=><button key={site} className={selectedSites.includes(site)?'selected':''} {...(site==='54 Career Sites'?{'data-tip':SITE_DESCRIPTIONS[site]}:{})} onClick={()=>toggleSite(site)}>{selectedSites.includes(site)?<CheckCircle2 size={13}/>:<Circle size={13}/>} {site}</button>)}</div></div></div>:<div className="import-links-layout refined-import"><div className="import-drop"><Upload size={18}/><strong>Paste or upload job links</strong><p>Accepts .md, .csv, .pdf, or .txt. HuntBrief extracts URLs, dedupes them, then organizes every posting for the downstream flow.</p><textarea value={importText} onChange={e=>setImportText(e.target.value)} placeholder={'https://company.com/careers/job-1\nhttps://boards.greenhouse.io/acme/jobs/123'} /><div className="actions"><button onClick={()=>importFileRef.current?.click()}>Upload file</button><button className="primary" onClick={()=>void importJobs()} disabled={!importText.trim()}>Extract jobs</button><small>{extractedLinks} links detected</small></div></div><div className="settings-warning">Tavily extraction is configured from the app Settings in the lower-left sidebar.</div></div>}{importResult&&<div className="import-note">{importResult.imported} imported · {importResult.skipped} skipped</div>}</div>;
}

function HuntProgressDashboard({progress,onOpen,onReset}:{progress:HuntProgress;onOpen:()=>void;onReset:()=>void}){ return <div className="hunt-status-dashboard"><div className="hunt-status-head"><div><small>Start Hunting</small><h3>{progress.title}</h3></div><strong>{progress.progress}%</strong></div><div className="hunt-status-track"><span style={{width:`${progress.progress}%`}}/></div><p>{progress.detail}</p><div className="hunt-status-steps">{progress.steps.map(step=><div key={step.label} className={`hunt-status-step ${step.status}`}><span>{step.status==='done'?<CheckCircle2 size={13}/>:step.status==='error'?<Circle size={13}/>:step.status==='active'?<span className="mini-spinner"/>:<Circle size={13}/>}</span><div>{step.label}</div></div>)}</div>{!progress.running&&<div className="hunt-status-actions"><button onClick={onReset}>Start another hunt</button>{progress.resultPath&&<button className="primary" onClick={onOpen}>Open results.md</button>}</div>}</div> }

function Connection({name,connected,busy,detail,onToggle}:{name:string;connected:boolean;busy?:boolean;detail:string;onToggle:()=>void|Promise<void>}){ return <div className="connection-chip"><span className={`status-dot ${connected?'on':''}`}/><div><strong>{name}</strong><small>{detail}</small></div><button disabled={busy} onClick={()=>void onToggle()}>{busy?<span className="mini-spinner"/>:connected?'Disconnect':'Connect'}</button></div> }
function EditorView({selectedPath,content,setContent,readOnly,dirty,saveFile,debugLogs}: any){ return <div className="editor-shell"><div className="editor-top"><div><span className="breadcrumb">{selectedPath || 'No file selected'}</span>{dirty && <span className="dirty">Unsaved</span>}</div><button disabled={!selectedPath||readOnly} onClick={saveFile}><Save size={14}/> Save</button></div><div className="editor-content">{!selectedPath?<div className="empty-editor"><h2>Select a file</h2><p>Use the file tree on the left, or generate/import hunting files from the project panel above.</p></div>:readOnly?<div className="readonly"><FileText size={24}/><h3>Read-only file</h3><p>Preview/editing is not supported for this file type yet.</p></div>:<textarea className="editor" value={content} onChange={e=>setContent(e.target.value)} spellCheck={false}/>}</div><div className="debug-console"><div className="debug-head">Debug log</div>{debugLogs?.length ? debugLogs.map((l:string,i:number)=><div key={i}>{l}</div>) : <div className="muted">No debug events yet.</div>}</div></div> }
function AgentPanel({project,selectedPath,setStatus,debugLog,refreshTree,openPath,onStartHunting}:{project:Project|null;selectedPath:string;setStatus:(s:string)=>void;debugLog:(s:string)=>void;refreshTree:()=>Promise<void>;openPath:(p:string)=>Promise<void>;onStartHunting:(name:string)=>Promise<HuntRunOutput|null>}){ const [draft,setDraft]=React.useState(''); const [messages,setMessages]=React.useState<ChatMessage[]>([]); const [sessions,setSessions]=React.useState<ChatSession[]>([]); const [sessionId,setSessionId]=React.useState(''); const [agentThinking,setAgentThinking]=React.useState(false); const [agentModel,setAgentModel]=React.useState('gpt-5.5'); const [thinkingMode,setThinkingMode]=React.useState('low'); const [runId,setRunId]=React.useState(''); const [runText,setRunText]=React.useState(''); const [runSteps,setRunSteps]=React.useState<string[]>([]); const [menuOpen,setMenuOpen]=React.useState(false); const [huntNameOpen,setHuntNameOpen]=React.useState(false); const [huntName,setHuntName]=React.useState('Remote Frontend Hunt'); const [deleteSessionId,setDeleteSessionId]=React.useState<string|null>(null); const [mentionOpen,setMentionOpen]=React.useState(false); const [mentionItems,setMentionItems]=React.useState<FileTreeNode[]>([]); const fileInputRef=React.useRef<HTMLInputElement|null>(null); const runBufferRef=React.useRef(''); const runIdRef=React.useRef(''); const firstDeltaLoggedRef=React.useRef(false); const activeSession=sessions.find(s=>s.id===sessionId); const flatten=(n:FileTreeNode):FileTreeNode[]=>{ const hidden=['project.json','profile','chats','sources','.DS_Store']; if(n.path&&hidden.includes(n.name))return[]; return [n,...(n.children||[]).flatMap(flatten)]; }; const loadMessages=React.useCallback((sid:string)=>{ if(project&&sid) call<ChatMessage[]>('list_chat_messages',{input:{projectSlug:project.slug,sessionId:sid}}).then(setMessages).catch(e=>setStatus(String(e))); },[project,setStatus]); React.useEffect(()=>{ if(!project){setSessions([]);setMessages([]);setSessionId('');return;} call<ChatSession[]>('list_chat_sessions',{projectSlug:project.slug}).then(ss=>{setSessions(ss); const sid=ss[0]?.id||''; setSessionId(sid); if(sid) loadMessages(sid);}).catch(e=>setStatus(String(e))); },[project,setStatus,loadMessages]); const newSession=async()=>{ if(!project)return; try{ const s=await call<ChatSession>('create_chat_session',{input:{projectSlug:project.slug,title:null}}); setSessions(prev=>[s,...prev]); setSessionId(s.id); setMessages([]); setMenuOpen(false); setStatus(`Created agent session ${s.title}`); }catch(e){setStatus(String(e));} }; const deleteSession=async()=>{ if(!project||!deleteSessionId)return; try{ await call('delete_chat_session',{input:{projectSlug:project.slug,sessionId:deleteSessionId}}); const ss=await call<ChatSession[]>('list_chat_sessions',{projectSlug:project.slug}); setSessions(ss); const sid=ss[0]?.id||''; setSessionId(sid); if(sid) loadMessages(sid); setDeleteSessionId(null); setMenuOpen(false); setStatus('Deleted agent session'); }catch(e){setStatus(String(e));} }; const send=async()=>{ if(!project||!draft.trim()||agentThinking)return; const userText=draft; try{ debugLog(`Agent send: saving user message (${userText.length} chars)`); const m=await call<ChatMessage>('save_chat_message',{input:{projectSlug:project.slug,sessionId:sessionId||null,role:'user',content:userText,linkedFilePath:selectedPath||null,linkedJobId:null}}); setMessages(prev=>[...prev,m]); setDraft(''); setMentionOpen(false); setAgentThinking(true); setRunText(''); firstDeltaLoggedRef.current=false; setRunSteps(['Starting Codex']); setStatus('Agent is working…'); const id=crypto.randomUUID(); runIdRef.current=id; setRunId(id); debugLog(`Agent run starting: ${id}`); const onEvent = new Channel<AgentRunEvent>(); onEvent.onmessage = (ev) => void handleAgentEvent(ev); const returnedId=await call<string>('start_agent_run',{input:{projectSlug:project.slug,prompt:userText,linkedFilePath:selectedPath||null,model:agentModel,effort:thinkingMode,runId:id},onEvent}); debugLog(`Agent run started: ${returnedId}`); window.setTimeout(()=>{ if(runIdRef.current===id&&!runBufferRef.current) debugLog('Agent watchdog 10s: no assistant delta yet; check latest Agent event/status above'); },10000); window.setTimeout(()=>{ if(runIdRef.current===id&&!runBufferRef.current) debugLog('Agent watchdog 25s: still no assistant delta; Codex may be waiting on thread/start, MCP startup, auth, or network'); },25000); }catch(e){setAgentThinking(false); debugLog(`Agent send failed: ${String(e)}`); setStatus(String(e));} };
  const stopRun=async()=>{ const id=runIdRef.current||runId; if(id) { debugLog(`Cancelling agent run: ${id}`); await call('cancel_agent_run',{input:{runId:id}}).catch(e=>debugLog(`Cancel failed: ${String(e)}`)); setAgentThinking(false); setRunId(''); runIdRef.current=''; } }; const addAttachment=(file:File|null)=>{ if(!file)return; setDraft(d=>`${d}${d?'\n':''}@attachment:${file.name}`); }; const onDraft=(v:string)=>{ setDraft(v); if(v.endsWith('@')&&project){ call<FileTreeNode>('list_workspace_tree',{projectSlug:project.slug}).then(t=>{setMentionItems(flatten(t).filter(n=>n.path));setMentionOpen(true);}).catch(()=>{}); } }; const insertMention=(path:string)=>{ setDraft(d=>d.replace(/@$/,`@${path} `)); setMentionOpen(false); }; React.useEffect(()=>{ const onKey=(e:KeyboardEvent)=>{ if(e.key==='Escape'){setMenuOpen(false);setDeleteSessionId(null);setMentionOpen(false);} }; window.addEventListener('keydown',onKey); return()=>window.removeEventListener('keydown',onKey); },[]);
  const handleAgentEvent=React.useCallback(async (ev:AgentRunEvent)=>{ const activeId=runIdRef.current; if(!activeId||ev.runId!==activeId||!project)return; if(ev.kind!=='delta') debugLog(`Agent event: ${ev.kind} ${ev.text.slice(0,80)}`); if(ev.kind==='stdout'||ev.kind==='delta'){ if(ev.kind==='delta'&&!firstDeltaLoggedRef.current){ firstDeltaLoggedRef.current=true; debugLog('Agent event: first assistant delta received; streaming response…'); } runBufferRef.current += ev.kind==='delta' ? ev.text : `${ev.text}\n`; setRunText(runBufferRef.current); } else if(ev.kind==='stderr'||ev.kind==='status'){ setRunSteps(prev=>[...prev, ev.text].slice(-6)); if(ev.kind==='stderr') debugLog(`Agent stderr: ${ev.text}`); } else if(ev.kind==='started'){ setRunSteps(prev=>[...prev, ev.text]); } else if(ev.kind==='completed'){ const content=runBufferRef.current.trim() || 'Done.'; const a=await call<ChatMessage>('save_chat_message',{input:{projectSlug:project.slug,sessionId:sessionId||null,role:'assistant',content,linkedFilePath:selectedPath||null,linkedJobId:null}}); setMessages(prev=>[...prev,a]); setAgentThinking(false); setRunId(''); runIdRef.current=''; setRunText(''); runBufferRef.current=''; debugLog('Agent run completed and saved'); } else if(ev.kind==='failed'||ev.kind==='cancelled'){ const content=ev.kind==='cancelled'?'Agent run cancelled.':`Codex failed: ${ev.text}`; const a=await call<ChatMessage>('save_chat_message',{input:{projectSlug:project.slug,sessionId:sessionId||null,role:'assistant',content,linkedFilePath:selectedPath||null,linkedJobId:null}}); setMessages(prev=>[...prev,a]); setAgentThinking(false); setRunId(''); runIdRef.current=''; setRunText(''); runBufferRef.current=''; debugLog(content); } },[project,sessionId,selectedPath,debugLog]); return <aside className="chat"><input ref={fileInputRef} type="file" hidden onChange={e=>addAttachment(e.target.files?.[0]||null)}/><div className="hunt-button-wrap"><button className="start-hunting" disabled={!project} onClick={()=>setHuntNameOpen(true)}><Play size={16}/> Start Hunting</button></div><div className="chat-head"><MessageSquare size={15}/><div className="agent-session-picker"><button className="session-trigger" disabled={!project} onClick={()=>setMenuOpen(!menuOpen)}><span>{activeSession?.title||'Agent Session'}</span><ChevronRight size={13}/></button>{menuOpen&&<div className="session-menu">{sessions.map(s=><div className="session-option" key={s.id} onContextMenu={e=>{e.preventDefault();setDeleteSessionId(s.id);}}><button onClick={()=>{setSessionId(s.id);loadMessages(s.id);setMenuOpen(false);}}>{s.title}</button><button className="session-delete" onClick={()=>setDeleteSessionId(s.id)}><Trash2 size={12}/></button></div>)}</div>}</div><button className="new-chat-button" disabled={!project} onClick={newSession} title="New chat session"><Plus size={14}/></button></div><div className="chat-body">{selectedPath && <div className="context-chip">File · {selectedPath}</div>}{messages.length===0&&<div className="agent-empty"><p>Start with a task. The agent can use visible project files, resources, and hunt context.</p></div>}{messages.map(m=>m.role==='user'?<div className="transcript-user" key={m.id}><p>{m.content}</p></div>:<div className="transcript-agent" key={m.id}><p>{m.content}</p><small>{new Date(m.createdAt).toLocaleString()}</small></div>)}{agentThinking&&<div className="agent-run"><div><span className="pi-spinner"/> Working</div>{runText&&<pre>{runText}</pre>}</div>}</div><div className="chat-compose agent-compose"><textarea aria-label="Project chat composer" value={draft} onChange={e=>onDraft(e.target.value)} onKeyDown={e=>{if(e.key==='Enter'&&!e.shiftKey){e.preventDefault();void send();}}} placeholder="Add a follow-up, attach files, or reference @..."/>{mentionOpen&&<div className="mention-menu">{mentionItems.slice(0,12).map(n=><button key={n.path} onClick={()=>insertMention(n.path)}>{n.kind==='directory'?'Folder':'File'} · {n.path}</button>)}</div>}<div className="compose-bottom"><div className="agent-controls"><select value={agentModel} onChange={e=>setAgentModel(e.target.value)} disabled={agentThinking}><option value="gpt-5.5">GPT-5.5</option><option value="gpt-5">GPT-5</option><option value="gpt-5-mini">GPT-5 mini</option></select><select value={thinkingMode} onChange={e=>setThinkingMode(e.target.value)} disabled={agentThinking}><option value="low">Low</option><option value="medium">Medium</option><option value="high">High</option></select></div><button className="attach-button" onClick={()=>fileInputRef.current?.click()} disabled={!project} title="Add image or file"><Paperclip size={15}/></button><button className={`send-arrow ${agentThinking?'stop':''}`} onClick={()=>agentThinking?void stopRun():void send()} disabled={!project||(!agentThinking&&!draft.trim())} title={agentThinking?'Stop':'Send'}>{agentThinking?'■':<Send size={15}/>}</button></div></div>{huntNameOpen&&<Portal><div className="modal-backdrop" onClick={()=>setHuntNameOpen(false)}><div className="native-sheet" onClick={e=>e.stopPropagation()}><strong>Name this hunt</strong><p>This creates a folder under <code>hunt_run/</code> with results.md.</p><input autoFocus value={huntName} onChange={e=>setHuntName(e.target.value)} onKeyDown={e=>{if(e.key==='Enter'&&huntName.trim()){setHuntNameOpen(false);debugLog(`Start Hunting: user named run "${huntName.trim()}"`);void onStartHunting(huntName.trim()).then(out=>{ if(out) debugLog(`Start Hunting: backend task prepared ${out.folderPath}`); });} if(e.key==='Escape')setHuntNameOpen(false);}} placeholder="Remote Frontend Hunt"/><div className="popover-actions"><button onClick={()=>setHuntNameOpen(false)}>Cancel</button><button className="primary" disabled={!huntName.trim()} onClick={()=>{setHuntNameOpen(false);debugLog(`Start Hunting: user named run "${huntName.trim()}"`);void onStartHunting(huntName.trim()).then(out=>{ if(out) debugLog(`Start Hunting: backend task prepared ${out.folderPath}`); });}}>Create hunt run</button></div></div></div></Portal>}{deleteSessionId&&<Portal><div className="modal-backdrop" onClick={()=>setDeleteSessionId(null)}><div className="native-sheet" onClick={e=>e.stopPropagation()}><strong>Delete agent session?</strong><p>This removes the selected session and its messages from SQLite.</p><div className="popover-actions"><button onClick={()=>setDeleteSessionId(null)}>Cancel</button><button className="danger-button" onClick={()=>void deleteSession()}>Delete</button></div></div></div></Portal>}</aside>; }
